INSERT INTO "public"."failures" ("id", "title", "year", "company", "role", "description", "lessons", "image_url", "order_index", "category", "is_unlocked", "published", "created_at", "updated_at", "phase", "project_type", "situation", "task", "result", "contributions", "key_results", "tags", "metrics", "company_url", "project_url", "report_url", "demo_url", "company_label", "project_label", "report_label", "demo_label", "company_urls", "project_urls", "report_urls", "demo_urls", "video_poster", "video_fallback") VALUES ('049ddab3-91e8-4630-bb67-4ac9af45096f', '10MS Notification System', 2023, '10 Minute School', 'Lead Product Manager', 'Failed due to moving priorities and tech debt of webengage', 'Notification systems require careful prioritization and technical debt management. Moving priorities can derail even well-planned features.', null, 1, 'Product Development', true, true, '2025-10-21 16:48:51.471344+00', '2025-10-21 16:48:51.471344+00', 'Discontinued', 'Notification System', 'Need for improved user engagement through better notification system, but existing WebEngage integration had significant technical debt.', 'Design and implement comprehensive notification system to improve user engagement and retention.', 'Project discontinued due to shifting priorities and technical constraints from existing WebEngage platform.', null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null), ('66fe8842-11fa-4478-af9a-162c71af7733', 'Jobs recommendation by BDJobs', 2023, '10 Minute School', 'Lead Product Manager', 'Due to lack of quality traffic and meaningful CVR', 'Partnership success depends on traffic quality, not just volume. Meaningful conversion rates require aligned user intent and value proposition.', null, 2, 'Partnership', true, true, '2025-10-21 16:48:51.471344+00', '2025-10-21 16:48:51.471344+00', 'Discontinued', 'Job Recommendation', 'Partnership with BDJobs to provide job recommendations to users, but struggled with traffic quality and conversion rates.', 'Establish partnership with BDJobs to integrate job recommendations into the platform for user value.', 'Partnership discontinued due to insufficient traffic quality and low conversion rates that didn''t justify continued investment.', null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null);